const Component = () => {
  // Fetch CPU usage data with 5-second auto-refresh
  // Replace 'YOUR_DATASOURCE_ID' with actual datasource ID
  const { data, loading, error, cached } = useData({
    datasourceId: 'YOUR_DATASOURCE_ID',
    query: {
      table: 'system_metrics',
      metric: 'cpu_usage',
      aggregation: 'avg',
      interval: '1m',
      startTime: new Date(Date.now() - 3600000), // Last hour
      endTime: new Date()
    },
    refreshInterval: 5000 // Refresh every 5 seconds
  });

  // Loading state
  if (loading && !data) {
    return (
      <div style={{
        padding: '20px',
        textAlign: 'center',
        color: '#f4f4f4'
      }}>
        Loading CPU usage data...
      </div>
    );
  }

  // Error state
  if (error) {
    return (
      <div style={{
        padding: '20px',
        border: '2px solid #da1e28',
        borderRadius: '4px',
        backgroundColor: '#2d0709',
        color: '#ffb3b8'
      }}>
        <strong>Error:</strong> {error.message}
      </div>
    );
  }

  // No data state
  if (!data || data.length === 0) {
    return (
      <div style={{
        padding: '20px',
        textAlign: 'center',
        color: '#c6c6c6'
      }}>
        No CPU usage data available
      </div>
    );
  }

  // Configure chart
  const option = {
    title: {
      text: 'CPU Usage Over Time',
      left: 'center',
      textStyle: {
        color: '#f4f4f4',
        fontSize: 16
      },
      subtext: cached ? '(Cached data)' : '(Live data)',
      subtextStyle: {
        color: '#8a3ffc',
        fontSize: 12
      }
    },
    tooltip: {
      trigger: 'axis',
      formatter: (params) => {
        const point = params[0];
        return `${point.name}<br/>CPU: ${point.value.toFixed(2)}%`;
      }
    },
    xAxis: {
      type: 'category',
      data: data.map(d => {
        const date = new Date(d.time);
        return date.toLocaleTimeString('en-US', { 
          hour: '2-digit', 
          minute: '2-digit' 
        });
      }),
      axisLabel: {
        color: '#c6c6c6',
        rotate: 45
      }
    },
    yAxis: {
      type: 'value',
      name: 'CPU %',
      nameTextStyle: {
        color: '#f4f4f4'
      },
      axisLabel: {
        color: '#c6c6c6',
        formatter: '{value}%'
      },
      min: 0,
      max: 100
    },
    series: [
      {
        name: 'CPU Usage',
        data: data.map(d => d.value),
        type: 'line',
        smooth: true,
        itemStyle: {
          color: '#0f62fe' // Carbon primary blue
        },
        areaStyle: {
          color: {
            type: 'linear',
            x: 0,
            y: 0,
            x2: 0,
            y2: 1,
            colorStops: [
              { offset: 0, color: 'rgba(15, 98, 254, 0.3)' },
              { offset: 1, color: 'rgba(15, 98, 254, 0.05)' }
            ]
          }
        }
      }
    ],
    grid: {
      left: '50px',
      right: '20px',
      bottom: '60px',
      top: '80px'
    }
  };

  return (
    <div style={{ width: '100%', height: '400px' }}>
      <ReactECharts 
        option={option} 
        theme="carbon-light"
        style={{ height: '100%', width: '100%' }}
      />
    </div>
  );
};
